1	<script lang="ts">
2		import type { PageData } from './$types';
3		import { goto } from '$app/navigation';
4		import { page } from '$app/stores';
5		import BeadDetail from '$lib/components/BeadDetail.svelte';
6	
7		let { data }: { data: PageData } = $props();
8	
9		function handleClose() {
10			const pathParts = $page.url.pathname.split('/');
11			pathParts.pop(); // remove beadId segment
12			const basePath = pathParts.join('/');
13			const searchStr = $page.url.searchParams.toString();
14			goto(searchStr ? `${basePath}?${searchStr}` : basePath);
15		}
16	</script>
17	
18	{#if data.bead}
19		<!-- Backdrop -->
20		<div
21			class="fixed inset-0 z-40 bg-black/20 dark:bg-black/40"
22			onclick={handleClose}
23			role="button"
24			tabindex="-1"
25			aria-label="Close panel"
26			onkeydown={(e) => e.key === 'Escape' && handleClose()}
27		></div>
28	
29		<!-- Detail panel — keyed on bead.id so navigation between beads remounts
30		     the component and its internal $state initializers see the new bead. -->
31		{#key data.bead.id}
32			<BeadDetail bead={data.bead} onClose={handleClose} executions={data.executions} nodeId={data.nodeId} projectId={data.projectId} />
33		{/key}
34	{/if}
