1	<script lang="ts">
2		import type { PageData } from './$types';
3		import { goto } from '$app/navigation';
4		import { page } from '$app/stores';
5		import { createClient } from '$lib/gql/client';
6		import { gql } from 'graphql-request';
7	
8		const BEADS_QUERY = gql`
9			query BeadsAllProjects($first: Int, $after: String, $status: String, $label: String, $projectID: String) {
10				beads(first: $first, after: $after, status: $status, label: $label, projectID: $projectID) {
11					edges {
12						node {
13							id
14							title
15							status
16							priority
17							labels
18							projectID
19						}
20						cursor
21					}
22					pageInfo {
23						hasNextPage
24						endCursor
25					}
26					totalCount
27				}
28			}
29		`;
30	
31		interface BeadNode {
32			id: string;
33			title: string;
34			status: string;
35			priority: number;
36			labels: string[] | null;
37			projectID: string | null;
38		}
39	
40		interface BeadEdge {
41			node: BeadNode;
42			cursor: string;
43		}
44	
45		interface PageInfo {
46			hasNextPage: boolean;
47			endCursor: string | null;
48		}
49	
50		interface BeadsResult {
51			beads: {
52				edges: BeadEdge[];
53				pageInfo: PageInfo;
54				totalCount: number;
55			};
56		}
57	
58		const STATUS_OPTIONS = ['open', 'in-progress', 'closed', 'blocked'];
59	
60		let { data }: { data: PageData } = $props();
61	
62		let appendedEdges = $state<BeadEdge[]>([]);
63		let appendedPageInfo = $state<PageInfo | null>(null);
64		let loadingMore = $state(false);
65	
66		// Reset appended pages on filter change
67		let filterKey = $derived(`${data.activeStatus}::${data.activeLabel}::${data.activeProject}`);
68		let prevFilterKey = $state('');
69		$effect(() => {
70			if (filterKey !== prevFilterKey) {
71				prevFilterKey = filterKey;
72				appendedEdges = [];
73				appendedPageInfo = null;
74			}
75		});
76	
77		let edges = $derived([...data.beads.edges, ...appendedEdges]);
78		let pageInfo = $derived<PageInfo>(appendedPageInfo ?? data.beads.pageInfo);
79		let totalCount = $derived(data.beads.totalCount);
80	
81		// Derive all unique labels from current result set
82		let allLabels = $derived(
83			Array.from(new Set(edges.flatMap((e) => e.node.labels ?? []))).sort()
84		);
85	
86		function setFilter(key: 'status' | 'label' | 'project', value: string | null) {
87			const params = new URLSearchParams($page.url.searchParams);
88			if (value === null) {
89				params.delete(key);
90			} else {
91				params.set(key, value);
92			}
93			params.delete('after');
94			const search = params.toString();
95			goto(search ? `?${search}` : $page.url.pathname, { replaceState: false });
96		}
97	
98		function toggleStatus(status: string) {
99			setFilter('status', data.activeStatus === status ? null : status);
100		}
101	
102		function toggleLabel(label: string) {
103			setFilter('label', data.activeLabel === label ? null : label);
104		}
105	
106		function toggleProject(projectId: string) {
107			setFilter('project', data.activeProject === projectId ? null : projectId);
108		}
109	
110		async function loadMore() {
111			if (!pageInfo.hasNextPage || loadingMore) return;
112			loadingMore = true;
113			try {
114				const client = createClient();
115				const result = await client.request<BeadsResult>(BEADS_QUERY, {
116					first: 20,
117					after: pageInfo.endCursor,
118					status: data.activeStatus ?? undefined,
119					label: data.activeLabel ?? undefined,
120					projectID: data.activeProject ?? undefined
121				});
122				appendedEdges = [...appendedEdges, ...result.beads.edges];
123				appendedPageInfo = result.beads.pageInfo;
124			} finally {
125				loadingMore = false;
126			}
127		}
128	
129		function statusClass(status: string): string {
130			switch (status) {
131				case 'open':
132					return 'text-blue-600 dark:text-blue-400';
133				case 'in-progress':
134					return 'text-yellow-600 dark:text-yellow-400';
135				case 'closed':
136					return 'text-green-600 dark:text-green-400';
137				case 'blocked':
138					return 'text-red-600 dark:text-red-400';
139				default:
140					return 'text-gray-500 dark:text-gray-400';
141			}
142		}
143	
144		function chipClass(active: boolean): string {
145			return active
146				? 'rounded-full border px-3 py-1 text-xs font-medium border-blue-500 bg-blue-50 text-blue-700 dark:border-blue-400 dark:bg-blue-900/30 dark:text-blue-300'
147				: 'rounded-full border px-3 py-1 text-xs font-medium border-gray-300 text-gray-600 hover:border-gray-400 hover:bg-gray-50 dark:border-gray-600 dark:text-gray-400 dark:hover:bg-gray-800';
148		}
149	
150		function projectName(projectID: string | null): string {
151			if (!projectID) return '—';
152			return data.projectNames[projectID] ?? projectID;
153		}
154	</script>
